import{_ as n,p as e,q as a,a1 as s}from"./framework-5866ffd3.js";const c={},o=s(`<h1 id="c-注释-comments" tabindex="-1"><a class="header-anchor" href="#c-注释-comments" aria-hidden="true">#</a> C 注释 Comments</h1><p>注释可用于解释代码，并使其更具可读性。它还可用于在测试替代代码时阻止执行。</p><p>注释可以是单行或多行的。</p><h2 id="单行注释" tabindex="-1"><a class="header-anchor" href="#单行注释" aria-hidden="true">#</a> 单行注释</h2><p>单行注释以两个正斜杠 (<code>//</code>) 开头。</p><p><code>//</code> 和行尾之间的任何文本都会被编译器忽略（不会被执行）。</p><p>此示例在一行代码之前使用单行注释：</p><div class="language-c line-numbers-mode" data-ext="c"><pre class="language-c"><code><span class="token comment">// 这是一个注释</span>
<span class="token function">printf</span><span class="token punctuation">(</span><span class="token string">&quot;Hello World!&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>此示例在代码行末尾使用单行注释：</p><div class="language-c line-numbers-mode" data-ext="c"><pre class="language-c"><code><span class="token function">printf</span><span class="token punctuation">(</span><span class="token string">&quot;Hello World!&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 这是一个注释</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="多行注释" tabindex="-1"><a class="header-anchor" href="#多行注释" aria-hidden="true">#</a> 多行注释</h2><p>多行注释以 <code>/*</code> 开头，以 <code>*/</code> 结尾。</p><p><code>/*</code> 和 <code>*/</code> 之间的任何文本都将被编译器忽略：</p><div class="language-c line-numbers-mode" data-ext="c"><pre class="language-c"><code><span class="token comment">/* 下面的代码将打印出 Hello World!
到屏幕上，真是太棒了 */</span>
<span class="token function">printf</span><span class="token punctuation">(</span><span class="token string">&quot;Hello World!&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="单行注释还是多行注释" tabindex="-1"><a class="header-anchor" href="#单行注释还是多行注释" aria-hidden="true">#</a> 单行注释还是多行注释？</h2><p>您要使用哪个取决于您。 通常，我们使用 <code>//</code> 表示简短的注释，使用 <code>/*</code> <code>*/</code> 表示较长的注释。</p><p>很高兴知道：在 C99 版本（1999 年发布）之前，您只能在 <code>C</code> 中使用多行注释。</p>`,17),t=[o];function d(i,p){return e(),a("div",null,t)}const r=n(c,[["render",d],["__file","c_comments.html.vue"]]);export{r as default};
